78	export function normalizeMarketListFilters(
79	  filters?: MarketListFilterInput,
80	): NormalizedMarketListFilters {
81	  const status = typeof filters === "string"
82	    ? filters
83	    : filters?.status;
84	  const includeResolved = (
85	    typeof filters !== "string"
86	    && filters?.includeResolved === true
87	  ) || status === "resolved";
88	  const sort = typeof filters !== "string" ? filters?.sort : undefined;
89	  const q = typeof filters !== "string" ? filters?.q?.trim() || undefined : undefined;
90	
91	  return {
92	    ...(status ? { status } : {}),
93	    ...(includeResolved ? { includeResolved: true } : {}),
94	    ...(sort ? { sort } : {}),
95	    ...(q ? { q } : {}),
96	  };
97	}
98	
99	function serializeMarketListFilters(filters?: MarketListFilterInput): string {
100	  const normalizedFilters = normalizeMarketListFilters(filters);
101	  const params = new URLSearchParams();
102	
103	  if (normalizedFilters.status) {
104	    params.set("status", normalizedFilters.status);
105	  }
106	
107	  if (normalizedFilters.includeResolved) {
108	    params.set("include_resolved", "true");
109	  }
110	
111	  if (normalizedFilters.sort) {
112	    params.set("sort", normalizedFilters.sort);
113	  }
114	
115	  if (normalizedFilters.q) {
116	    params.set("q", normalizedFilters.q);
117	  }
118	
119	  const queryString = params.toString();
120	  return queryString ? `?${queryString}` : "";
121	}
122	
123	export function listMarkets(
124	  filters?: MarketListFilterInput,
125	): Promise<MarketListResponse> {
